#!/usr/bin/env python3
"""Build amc12b_all.json from hardcoded problem data fetched from AoPS wiki."""
import json

def difficulty(n):
    if n <= 8: return "easy"
    if n <= 18: return "medium"
    return "hard"

problems = []

# ===== HELPER =====
def add_year(year, prob_list, answer_map, source_url, topic_map, variant=None):
    for num, text, choices in prob_list:
        ans = answer_map[num]
        idx = ord(ans) - ord('A')
        entry = {
            "contest": "AMC 12B",
            "year": year,
            "number": num,
            "topic": topic_map.get(num, "Algebra"),
            "difficulty": difficulty(num),
            "problem": text,
            "choices": choices,
            "correct_answer": ans,
            "correct_value": choices[idx],
            "solution": "See AoPS wiki for detailed solution.",
            "track": "math",
            "source_link": source_url
        }
        if variant:
            entry["variant"] = variant
        problems.append(entry)

